+fn define_hidden_property(
+    heap: &mut ObjectHeap,
+    handle: ObjectHandle,
+    name: &str,
+    value: JsValue,
+) -> Result<(), StdlibError> {
+    let defined = heap
+        .define_property(
+            handle,
+            PropertyKey::from(name),
+            PropertyDescriptor::Data {
+                value,
+                writable: true,
+                enumerable: false,
+                configurable: true,
+            },
+        )
+        .map_err(object_error)?;
+    if defined {
+        Ok(())
+    } else {
+        Err(StdlibError::TypeError(format!(
+            "failed to define hidden property `{name}`"
+        )))
+    }
+}
