+fn get_count_property(
+    heap: &ObjectHeap,
+    handle: ObjectHandle,
+    name: &str,
+) -> Result<usize, StdlibError> {
+    let value = get_required_own_data_property(heap, handle, name)?;
+    count_from_value(name, value)
